-- 1. Removal Companies × Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'removal-companies',
  'web-design',
  'When someone is moving house, they are typically stressed, time-pressured, and comparing multiple removal companies simultaneously. Your website has seconds to communicate trustworthiness, professionalism, and the ability to handle their specific move. A family moving a four-bedroom house full of antique furniture has entirely different concerns than a student moving a studio flat. A business relocating an office needs to see evidence of commercial capability, insurance coverage, and weekend availability. Most removal company websites are generic templates with a van photo and a phone number, providing no way for visitors to understand pricing, no indication of what size moves you handle, and no reassurance about how you treat valuable or fragile items. We build removal company websites that guide visitors through a clear journey: identify their move type, understand what is included, see evidence of similar moves completed successfully, and request a quote with the specific details you need to price accurately. The website pre-qualifies enquiries by move size, distance, and special requirements so every quote request arrives as a detailed brief rather than a vague please call me message.',
  'Removal companies operate in one of the most comparison-driven markets in the service sector. Customers typically request three to five quotes before deciding, and their first filter is your website. If your site looks dated, provides no pricing guidance, and offers no evidence of successfully handling moves similar to theirs, you are eliminated before you can even demonstrate your service quality. A professional website that addresses specific move types and concerns keeps you on the shortlist.',
  'We design removal company websites around move types rather than generic service lists. Domestic house moves, office relocations, long-distance moves, and specialist item transport each have dedicated pages with relevant imagery, specific pricing guidance, and appropriate trust signals. Instant quote calculators let visitors estimate costs before committing to a full survey.',
  '[{"title": "No way for visitors to estimate costs before requesting a quote", "description": "Moving house is expensive and customers want to understand approximate costs before committing their time to a full survey. When your website provides no pricing guidance whatsoever, visitors assume the worst and gravitate toward competitors who offer instant estimates or transparent pricing structures. The absence of any pricing information is itself a conversion barrier."}, {"title": "Generic presentation failing to address specific move anxieties", "description": "A family moving valuable antiques has different concerns than a couple moving from a one-bed flat. When your website presents a single generic message about removals, neither audience feels their specific concerns are understood. The antiques owner worries about damage. The flat mover worries about being overcharged for a small job. Generic messaging addresses neither."}, {"title": "No visual evidence of completed moves building trust", "description": "Removal companies handle people''s entire possessions, often including irreplaceable items with enormous sentimental value. Without photos of your team carefully handling furniture, professionally wrapped items, and well-organised vehicle loading, visitors cannot assess whether you will treat their belongings with the care they expect. Trust requires visual proof."}]',
  '[{"title": "Move-type specific pages with tailored messaging", "description": "Dedicated pages for house moves by size, flat and apartment moves, office relocations, long-distance and international moves, and specialist item transport. Each page addresses the specific concerns of that move type with relevant imagery, appropriate pricing guidance, and trust signals. Visitors immediately find content relevant to their exact situation."}, {"title": "Instant quote calculator with move-size estimation", "description": "An interactive tool where visitors select their current property size, destination distance, and any special requirements to receive an indicative price range. This engages visitors, sets pricing expectations, and captures their details for follow-up. The calculator pre-qualifies leads so your survey team arrives knowing the move scope and the customer''s budget expectations."}, {"title": "Visual trust gallery with careful handling evidence", "description": "A curated gallery showing your team wrapping furniture, protecting fragile items, loading vehicles methodically, and delivering moves successfully. Before-and-after photos of office relocations demonstrate commercial capability. Customer video testimonials add authentic social proof. Every image reinforces the care and professionalism that justifies your pricing."}]',
  '[{"question": "Should we show prices on our removal company website?", "answer": "We recommend showing indicative price ranges rather than fixed prices. A price calculator giving approximate costs based on property size and distance sets expectations and engages visitors. Exact pricing after a survey is standard in the industry, but providing no guidance whatsoever loses visitors who want to understand the ballpark before committing their time."}, {"question": "How do you build trust for a removal company website?", "answer": "Trust is built through visible evidence: photos of careful packing and handling, customer testimonials with specific move details, displayed insurance coverage and BAR membership, and a professional presentation that communicates organisation and care. We also integrate Google reviews directly into the website to provide ongoing, independent social proof."}, {"question": "Can the website handle different types of moves separately?", "answer": "Absolutely. Domestic house moves, flat moves, office relocations, long-distance moves, and specialist transport each have dedicated pages. This ensures visitors find content relevant to their specific move type and see evidence that you have successfully handled similar moves before."}, {"question": "How does the instant quote calculator work?", "answer": "Visitors select their property size from a visual guide, enter their origin and destination postcodes, and indicate any special requirements like piano moves or antique furniture. The calculator provides an indicative price range and captures their details for your team to follow up with a full survey. It generates qualified leads with move details already captured."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Removal Companies × SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'removal-companies',
  'seo',
  'Removal company searches are among the most high-intent local queries you can target. When someone searches for removal companies near me or house removals Kent, they have a confirmed moving date and are actively comparing companies to hire. These are not casual browsers; they are people who will book a removal company within days. The challenge is that this market is fiercely competitive, with national brands, directory sites, and comparison platforms dominating many search results. Local removal companies can compete by exploiting the geographic specificity and service breadth that national competitors cannot match. Searches for removals from Maidstone to London, two-bedroom flat removals Canterbury, or office relocation Tunbridge Wells represent exact-match local intent that a well-optimised local website can capture ahead of national directories. Our SEO campaigns for removal companies target every combination of move type, property size, and location that drives search volume in your area. We also build seasonal strategies around peak moving periods, student moving seasons, and end-of-tenancy cycles that create predictable demand surges throughout the year.',
  'The removal industry has strong seasonal patterns that make SEO particularly valuable. Spring and summer see the highest moving volumes. September brings student moves. End-of-tenancy cycles create predictable demand spikes. Companies that rank well for removal searches during these peak periods capture the lion''s share of annual revenue. Those invisible during peaks rely on whatever work reaches them through word of mouth and directories, missing the most profitable weeks of the year.',
  'We build SEO strategies around the geographic routes and move types that define your business. Route-specific pages target searches between your service area and common destinations. Property-size pages capture searches from studio flat moves to six-bedroom house removals. Seasonal content anticipates demand peaks and captures early-stage planning searches.',
  '[{"title": "Invisible for high-intent moving day searches in your area", "description": "When a homeowner with a confirmed completion date searches for removal companies plus their town name, they are days away from booking. The removal companies appearing in the top three organic positions and the Google Map Pack capture the majority of these bookings. If your business is not visible for these searches, you are surrendering your most valuable leads to better-optimised competitors."}, {"title": "National directories and comparison sites outranking your website", "description": "Reallymoving, Compare My Move, and similar platforms dominate many removal search terms because they invest heavily in SEO. As a local removal company, you cannot outspend these platforms, but you can outrank them for specific local route and move-type combinations where their generic content cannot compete with your detailed, locally-specific pages."}, {"title": "No content targeting seasonal demand peaks and planning-stage searches", "description": "The months before peak moving season see significant search volume from people planning ahead. Searches like how much do removals cost, what size van do I need for a three-bed house, and moving house checklist represent early-stage prospects who will book within weeks. Without content targeting these planning searches, you miss the opportunity to capture customers before they reach the comparison stage."}]',
  '[{"title": "Route-specific and area-focused landing pages", "description": "Dedicated pages targeting the most common moving routes from your service area. Removals from Maidstone to London, Canterbury to Brighton, Tunbridge Wells to Manchester, and every significant route you serve. Each page includes estimated journey times, pricing guidance, and route-specific information that national directories cannot replicate."}, {"title": "Property-size and move-type targeted content", "description": "Individual pages optimised for searches by property size: one-bed flat removals, three-bedroom house moves, five-bedroom house removals, and similar terms. Additional pages target office relocations, student moves, and specialist item transport. Each page captures the specific long-tail search terms that drive high-intent traffic for that move type."}, {"title": "Seasonal SEO strategy with peak-period content", "description": "Content published ahead of peak moving periods targeting planning-stage searches. Spring moving guides published in January capture early planners. Student moving content published in July captures September moves. End-of-tenancy removal guides target the predictable cycles that drive rental market moves. This seasonal approach captures demand before competitors activate."}]',
  '[{"question": "How competitive is SEO for removal companies?", "answer": "The main search terms like removal companies near me are competitive, but the long-tail opportunity is enormous. Route-specific searches, property-size queries, and move-type terms are far less competitive and collectively drive more total traffic than the head terms. We focus on building comprehensive coverage across these specific, high-converting search terms."}, {"question": "Can we rank above comparison sites like Reallymoving?", "answer": "For specific local and route-based searches, absolutely. National comparison sites produce generic content that cannot match the local detail, route knowledge, and service specificity of a dedicated local removal company page. We target the searches where your local expertise gives you a content advantage that directories cannot replicate."}, {"question": "How important is Google Business Profile for a removal company?", "answer": "Critical. The Google Map Pack appears for most removal-related searches and drives significant call volume. We optimise your Google Business Profile with accurate service areas, move-type categories, professional photography, and a review generation strategy that builds the volume and quality of reviews needed to appear in the Map Pack consistently."}, {"question": "How long before SEO generates consistent removal enquiries?", "answer": "Google Business Profile improvements can increase visibility within four to six weeks. Route-specific landing pages typically begin ranking within two to four months. Peak seasonal terms require content published several months ahead of the season. Most removal companies see meaningful traffic increases within three to four months, with compounding growth over the first year."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 3. Removal Companies × Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'removal-companies',
  'lead-capture',
  'Removal companies face a distinct lead capture challenge: every customer is comparing you against multiple competitors simultaneously. The average person moving house requests three to five quotes, which means your ability to respond quickly with relevant, detailed information directly determines your conversion rate. A quote request that sits in your inbox for twenty-four hours while competitors respond within an hour is a quote request you have already lost. Lead capture for removal companies must do two things exceptionally well: capture enough detail to provide an accurate estimate quickly, and create an immediate response that keeps you top of mind during the customer''s comparison process. Our lead capture systems collect move date, property sizes at origin and destination, distance, access details, special items, and packing requirements through an engaging multi-step form. The moment a submission arrives, an automated response confirms receipt, provides an indicative price range based on the details given, and sets expectations for the full survey process. This instant engagement separates you from every competitor whose response is a generic we will be in touch email sent manually hours later.',
  'Speed of response is the single largest factor determining which removal company wins the booking. Research shows that the first company to respond with a substantive reply captures the enquiry in the majority of cases. When a customer submits five quote requests, the company that responds within minutes with an indicative estimate and a professional follow-up process wins, even against lower-priced competitors who respond the next day.',
  'We build lead capture that provides instant value to the customer. Multi-step forms collect detailed move information through an engaging, easy-to-complete process. Automated responses include indicative pricing based on the details provided, your availability around their moving date, and clear next steps for the survey process. Speed and substance win removals quotes.',
  '[{"title": "Quote requests arriving with insufficient information for pricing", "description": "A message saying I need a quote for a house move gives you nothing to work with. You do not know the property size, the destination, the moving date, whether there are access restrictions, or whether they need packing services. You are forced to call back and spend fifteen minutes gathering information that a structured form would capture instantly."}, {"title": "Slow response to quote requests while customers compare competitors", "description": "Customers requesting removal quotes are actively comparing. They submit multiple requests and engage with whichever company responds first with useful information. If your response takes twelve or twenty-four hours because you are on a job all day, the customer has already built a relationship with a faster competitor before you even reply."}, {"title": "No follow-up system for quotes that do not convert immediately", "description": "Moving dates are often weeks or months away. A customer who requests a quote in January for an April move needs periodic follow-up to keep your company in consideration. Without an automated nurture sequence, these advance enquiries are quoted once and forgotten, with the customer eventually booking whichever company contacts them closest to their moving date."}]',
  '[{"title": "Detailed multi-step quote request form with instant estimates", "description": "An engaging form that guides visitors through their move details: property sizes, postcodes, moving date, access conditions, special items, and packing requirements. On submission, the system calculates and displays an indicative price range based on the information provided. This instant value keeps the customer engaged while your team prepares a full survey-based quote."}, {"title": "Automated rapid-response sequence with personalised content", "description": "Within seconds of submission, the customer receives a personalised email confirming their move details, an indicative price range, your availability around their requested date, and clear next steps. A follow-up message introduces your survey process and team. This two-step immediate response establishes your company as professional and responsive before competitors have even read their enquiry."}, {"title": "Quote nurture system for advance bookings and undecided customers", "description": "Customers who receive a quote but do not book immediately enter a tailored nurture sequence. Periodic emails offer helpful moving tips, packing advice, and gentle reminders as their moving date approaches. The sequence intensifies in the final weeks before the move, ensuring your company remains top of mind when the customer is ready to confirm their booking."}]',
  '[{"question": "How does the instant estimate work before a proper survey?", "answer": "The form collects property sizes, postcodes, floor levels, access conditions, and special items. Using your pricing matrix, the system calculates an indicative range based on these factors. The estimate is presented as a guide pending a full survey, setting accurate expectations while providing the immediate pricing information customers want."}, {"question": "Can the form capture details about specialist items like pianos or antiques?", "answer": "Yes. The form includes a specialist items section where customers can indicate pianos, antiques, fragile artwork, heavy safes, hot tubs, and other items requiring special handling. This information helps you prepare an accurate quote and ensures your survey team knows what to assess when they visit the property."}, {"question": "How do you stop competitors from using the quote form to see our pricing?", "answer": "Instant estimates show a range rather than a fixed price, and full pricing requires a survey. The estimate is based on the specific move details entered, so a competitor would only see pricing for that exact scenario. The primary purpose is engaging genuine customers with immediate value, not publishing your rate card."}, {"question": "What happens with customers who request a quote months before their moving date?", "answer": "They enter a timed nurture sequence calibrated to their moving date. Early-stage emails provide moving preparation advice and packing tips. As the date approaches, the messaging shifts to availability confirmation, booking reminders, and moving day preparation. This sustained contact keeps your company front of mind throughout the entire planning period."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
