-- 6. Removal Companies × Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'removal-companies',
  'social-media-setup',
  'Removal companies have a unique social media advantage: moving house is an inherently shareable life event. Customers post about their moves, tag the companies involved, and share their experience with friends who may be moving soon. When someone announces they are moving house on Facebook, the comments section becomes a recommendation engine. If your removal company has an active, professional social presence, friends and past customers tag you in these conversations, generating referrals with the highest conversion rate of any marketing channel. The content opportunity is equally strong. A satisfied family standing in front of their new home with your branded van in the background is powerful social proof. A time-lapse video of your crew loading a house move showcases efficiency and care. A before-and-after of an office relocation demonstrates commercial capability. This content works because it shows real moves, real people, and real results. The challenge for most removal companies is capturing and posting this content consistently alongside the physical demands of running moves every day. We set up your social presence and create systems that make content capture part of the moving day workflow rather than an afterthought.',
  'Moving house is a life event that people discuss publicly on social media. When someone posts that they are moving, their friends share recommendations. Removal companies with active social profiles get tagged in these conversations, receiving referrals from trusted personal networks. Without a social presence, these organic recommendation opportunities pass you by entirely, directed instead to competitors whose profiles friends can easily tag and link to.',
  'We build social media presence around the shareable nature of moving day. Content capture checklists ensure crew photograph every completed move. Customer milestone posts celebrate successful moves and invite tagging. Local community group engagement positions your company where recommendation conversations naturally happen.',
  '[{"title": "Missing organic referral opportunities in local community groups", "description": "Every week, people post in local Facebook groups asking for removal company recommendations. These posts generate dozens of replies, and the companies that get tagged are those with visible, active profiles that friends can easily link to. Without a social presence, your satisfied past customers cannot easily refer you in these high-value recommendation threads."}, {"title": "Completed moves not being captured as social content", "description": "Every successful move is potential social media content: the loaded van ready to depart, the crew working efficiently, the happy family at their new home. But when your team finishes a move and drives straight to the next job, this content is never captured. Your best marketing material drives away with the empty van."}, {"title": "Reviews not being generated from satisfied customers at the point of delight", "description": "The moment a move is completed successfully and the customer is relieved and grateful is the highest point of satisfaction in the entire customer journey. If you do not request a review at this exact moment, the likelihood drops dramatically each day. Most removal companies collect no reviews systematically, relying on the rare customer who spontaneously leaves one."}]',
  '[{"title": "Professional profiles optimised for local recommendation visibility", "description": "Facebook, Instagram, and Google Business profiles set up with professional imagery, complete service descriptions, and displayed reviews. Profiles are optimised to appear when tagged in local community group recommendations. Cover images feature your branded fleet, and profile descriptions emphasise your local service area and move types."}, {"title": "Moving day content capture system for crew", "description": "A simple photo checklist integrated into your crew''s moving day workflow. Before loading, during the move, and at the new property, crew capture three to five photos per job. Images are submitted and batch-scheduled into professional social posts with customer permission. The system requires under two minutes per move and produces content for weeks of posting."}, {"title": "Post-move review generation at the point of customer delight", "description": "Immediately after a successful move, an automated sequence sends a thank-you message with direct links to leave reviews on Google and Facebook. The timing captures customers at their most satisfied and grateful. A follow-up one week later catches those who intended to leave a review but were distracted by the chaos of unpacking."}]',
  '[{"question": "What social media platforms matter most for removal companies?", "answer": "Facebook is essential because local community groups are where removal recommendations happen most frequently. Google Business posts improve local search visibility and collect reviews. Instagram provides a visual portfolio of completed moves. We set up all three as an integrated system, with Facebook receiving priority for community engagement and recommendation visibility."}, {"question": "How do we get crew to capture content during busy moving days?", "answer": "We create a three-photo checklist that takes under two minutes: one photo of the loaded van, one of the crew working, and one at the destination. Crew capture these on their phones at natural break points in the move. Photos are submitted through a simple process and scheduled into posts by your marketing system rather than requiring any extra effort from the crew."}, {"question": "Can satisfied customers be prompted to post about their move on social media?", "answer": "Yes. Post-move communications include a polite request to share their experience on social media and tag your company. Some removal companies offer a small incentive for tagged posts. The key is timing: asking immediately after the move when the customer is most relieved and grateful maximises the likelihood they will share their positive experience."}, {"question": "How do we handle it when someone in a local group asks for removal recommendations?", "answer": "Your active social presence means past customers can tag your page directly in recommendation threads. We also set up monitoring for local group recommendation requests so you or your team can respond with helpful information rather than a hard sell. Providing useful advice about moving preparation in these threads builds credibility and generates enquiries naturally."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
